1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	interface Damage {
14	  itemType: string;
15	  amount: number;
16	}
17	
18	interface ClaimStep {
19	  op: "claim";
20	  policy: number;
21	  incident: { cause: string; damages: Damage[] };
22	}
23	
24	type Step = QuoteStep | ClaimStep;
25	
26	interface Scenario {
27	  customer: { yearsWithMHPCO: number };
28	  steps: Step[];
29	}
30	
31	const BASE_PREMIUM: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	  rune: 25,
37	  moonstone: 25,
38	};
39	
40	const INSURANCE_VALUE: Record<string, number> = {
41	  sword: 1000,
42	  amulet: 600,
43	  staff: 800,
44	  potion: 400,
45	  rune: 250,
46	  moonstone: 250,
47	};
48	
49	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
50	const BLOCK_SIZE = 3;
51	const BLOCK_PREMIUM = 60;
52	const DEDUCTIBLE = 100;
53	const CAP_MULTIPLIER = 2;
54	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
55	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
56	const FULL_REIMBURSEMENT_RATE = 1;
57	
58	const FIRST_INSURANCE_SURCHARGE = 0.1;
59	const CURSE_SURCHARGE = 0.5;
60	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
61	const HIGH_ENCHANTMENT_THRESHOLD = 5;
62	const LOYALTY_DISCOUNT = 0.2;
63	const LOYALTY_THRESHOLD_YEARS = 2;
64	const FOLLOWUP_DISCOUNT = 0.15;
65	const PROCESSING_FEE = 5;
66	
67	// Premiums are rounded up. We strip floating-point noise (e.g. 197.49999999)
68	// before rounding so that arithmetic artefacts don't push the result up a whole Gold.
69	const roundPremiumUp = (amount: number): number => Math.ceil(Number(amount.toFixed(6)));
70	
71	// Payouts are rounded down (in the office's favour), with the same float-noise guard.
72	const roundPayoutDown = (amount: number): number => Math.floor(Number(amount.toFixed(6)));
73	
74	// A block applies only to a group of exactly BLOCK_SIZE alike components,
75	// priced at BLOCK_PREMIUM; any other count is priced individually.
76	const componentBasePremium = (count: number, perComponent: number): number => {
77	  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
78	  return count * perComponent;
79	};
80	
81	const sum = (amounts: number[]): number => amounts.reduce((acc, amount) => acc + amount, 0);
82	
83	const isKnownItemType = (type: string): boolean => BASE_PREMIUM[type] !== undefined;
84	
85	// A quote may only insure item types the office prices. An unknown type has no
86	// premium or insurance value, so we reject the whole quote rather than guess.
87	const assertKnownItemTypes = (items: Item[]): void => {
88	  const unknown = items.find((item) => !isKnownItemType(item.type));
89	  if (unknown !== undefined) {
90	    throw new Error(`Unknown item type: ${unknown.type}`);
91	  }
92	};
93	
94	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
95	const isMainItem = (item: Item): boolean => !isComponent(item);
96	
97	// Tally how many values fall under each key the selector returns.
98	const countBy = <T>(values: T[], keyOf: (value: T) => string): Record<string, number> => {
99	  const counts: Record<string, number> = {};
100	  for (const value of values) {
101	    const key = keyOf(value);
102	    counts[key] = (counts[key] ?? 0) + 1;
103	  }
104	  return counts;
105	};
106	
107	const countByType = (items: Item[]): Record<string, number> =>
108	  countBy(items, (item) => item.type);
109	
110	// A surcharge rate is an additive percentage applied on top of a base premium.
111	const applySurcharge = (base: number, rate: number): number => base * (1 + rate);
112	
113	// A conditional rate: the given percentage when its condition holds, else 0.
114	// Used for both item surcharges and policy-wide discounts.
115	const rateWhen = (applies: boolean, rate: number): number => (applies ? rate : 0);
116	
117	// Item-specific surcharges are additive percentages of the item's base premium.
118	// First insurance applies to every item; the others only when their condition holds.
119	const itemSurchargeRate = (item: Item): number =>
120	  sum([
121	    FIRST_INSURANCE_SURCHARGE,
122	    rateWhen(item.cursed === true, CURSE_SURCHARGE),
123	    rateWhen((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, HIGH_ENCHANTMENT_SURCHARGE),
124	  ]);
125	
126	const mainItemPremium = (item: Item): number =>
127	  applySurcharge(BASE_PREMIUM[item.type], itemSurchargeRate(item));
128	
129	const componentGroupBases = (items: Item[]): number[] =>
130	  Object.entries(countByType(items.filter(isComponent))).map(([type, count]) =>
131	    componentBasePremium(count, BASE_PREMIUM[type]),
132	  );
133	
134	// Sum of item base premiums with block pricing but no surcharges; the basis
135	// for policy-wide modifiers (loyalty, follow-up).
136	const policyBasePremium = (items: Item[]): number =>
137	  sum(items.filter(isMainItem).map((item) => BASE_PREMIUM[item.type])) +
138	  sum(componentGroupBases(items));
139	
140	// Sum of item premiums including item-specific surcharges (curse, high
141	// enchantment, first insurance).
142	const itemsPremium = (items: Item[]): number => {
143	  const mainItemsPremium = sum(items.filter(isMainItem).map(mainItemPremium));
144	  const componentsPremium = sum(
145	    componentGroupBases(items).map((base) => applySurcharge(base, FIRST_INSURANCE_SURCHARGE)),
146	  );
147	  return mainItemsPremium + componentsPremium;
148	};
149	
150	// Policy-wide discounts are a rate applied to the unmodified policy base.
151	// Loyalty is one such discount; the follow-up-contract discount will be another.
152	const policyWideDiscount = (rate: number, policyBase: number): number => rate * policyBase;
153	
154	const loyaltyDiscountRate = (yearsWithMHPCO: number): number =>
155	  rateWhen(yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS, LOYALTY_DISCOUNT);
156	
157	const quotePremium = (items: Item[], yearsWithMHPCO: number, isFollowup: boolean): number => {
158	  const surcharged = itemsPremium(items);
159	  const policyBase = policyBasePremium(items);
160	  const discountRate = loyaltyDiscountRate(yearsWithMHPCO) + rateWhen(isFollowup, FOLLOWUP_DISCOUNT);
161	  const discount = policyWideDiscount(discountRate, policyBase);
162	  return roundPremiumUp(surcharged - discount + PROCESSING_FEE);
163	};
164	
165	const insuranceSum = (items: Item[]): number =>
166	  sum(items.map((item) => INSURANCE_VALUE[item.type]));
167	
168	const findInsuredItem = (policyItems: Item[], itemType: string): Item | undefined =>
169	  policyItems.find((item) => item.type === itemType);
170	
171	const isHighlyEnchanted = (item: Item | undefined): boolean =>
172	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
173	
174	// The damaged item's traits decide what fraction of the damage is reimbursed
175	// before the deductible. Clauses are checked in priority order, so the first
176	// matching one wins; a full reimbursement applies when none does.
177	const reimbursementRate = (item: Item | undefined): number => {
178	  if (isHighlyEnchanted(item)) return HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
179	  return FULL_REIMBURSEMENT_RATE;
180	};
181	
182	const reimbursement = (item: Item | undefined, amount: number): number =>
183	  amount * reimbursementRate(item);
184	
185	const damagePayout = (damage: Damage, item: Item | undefined): number =>
186	  Math.max(0, reimbursement(item, damage.amount) - DEDUCTIBLE);
187	
188	// A damage amount represents a loss, so it cannot be negative.
189	const assertDamageAmountsNonNegative = (damages: Damage[]): void => {
190	  const negative = damages.find((damage) => damage.amount < 0);
191	  if (negative !== undefined) {
192	    throw new Error(`Negative damage amount: ${negative.amount}`);
193	  }
194	};
195	
196	// A claim may only report as many damages of a type as the policy insures of
197	// that type; an uninsured type insures zero, so it is rejected too.
198	const assertDamagesWithinInsuredCounts = (policyItems: Item[], damages: Damage[]): void => {
199	  const insured = countByType(policyItems);
200	  const damaged = countBy(damages, (damage) => damage.itemType);
201	  const excessType = Object.keys(damaged).find((type) => damaged[type] > (insured[type] ?? 0));
202	  if (excessType !== undefined) {
203	    throw new Error(`Too many damages for item type: ${excessType}`);
204	  }
205	};
206	
207	// A claim is valid only if every damage is a non-negative loss and no item type
208	// is damaged more times than the policy insures it.
209	const assertClaimValid = (policyItems: Item[], incident: ClaimStep["incident"]): void => {
210	  assertDamageAmountsNonNegative(incident.damages);
211	  assertDamagesWithinInsuredCounts(policyItems, incident.damages);
212	};
213	
214	// The uncapped payout an incident would pay before the policy's remaining cap
215	// is applied: each damage reimbursed per its item's clause, less the deductible.
216	const incidentPayout = (policyItems: Item[], incident: ClaimStep["incident"]): number =>
217	  sum(
218	    incident.damages.map((damage) =>
219	      damagePayout(damage, findInsuredItem(policyItems, damage.itemType)),
220	    ),
221	  );
222	
223	interface Policy {
224	  items: Item[];
225	  remainingCap: number;
226	}
227	
228	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
229	  const { yearsWithMHPCO } = scenario.customer;
230	  const policies: Record<number, Policy> = {};
231	  let quoteCount = 0;
232	
233	  const handleQuote = (step: QuoteStep, index: number): { premium: number } => {
234	    assertKnownItemTypes(step.items);
235	    policies[index] = {
236	      items: step.items,
237	      remainingCap: CAP_MULTIPLIER * insuranceSum(step.items),
238	    };
239	    const isFollowup = quoteCount > 0;
240	    quoteCount += 1;
241	    return { premium: quotePremium(step.items, yearsWithMHPCO, isFollowup) };
242	  };
243	
244	  const handleClaim = (step: ClaimStep): { payout: number; remainingCap: number } => {
245	    const policy = policies[step.policy];
246	    assertClaimValid(policy.items, step.incident);
247	    const desiredPayout = incidentPayout(policy.items, step.incident);
248	    const payout = roundPayoutDown(Math.min(desiredPayout, policy.remainingCap));
249	    policy.remainingCap -= payout;
250	    return { payout, remainingCap: policy.remainingCap };
251	  };
252	
253	  const results = scenario.steps.map((step, index) =>
254	    step.op === "claim" ? handleClaim(step) : handleQuote(step, index),
255	  );
256	
257	  return { results };
258	};
